arguments.file_text:
@rendermode InteractiveServer

<div class="file-drop-zone @(_isDragOver ? "drag-over" : "")"
     @ondragover="HandleDragOver"
     @ondragover:preventDefault
     @ondragleave="HandleDragLeave"
     @ondrop="HandleDrop"
     @ondrop:preventDefault>
    <InputFile @ref="_inputFile" OnChange="HandleFileSelection" multiple style="display:none" />
    <p>Drag &amp; drop files here</p>
</div>

@if (_files.Count > 0)
{
    <ul class="file-list">
        @foreach (var entry in _files)
        {
            <li class="file-entry @(entry.Error is not null ? "file-error" : "")">
                @if (entry.Error is not null)
                {
                    <span class="file-name">@entry.Info.Name</span>
                    <span class="error-message">@entry.Error</span>
                }
                else
                {
                    <span class="file-name">@entry.Info.Name</span>
                    <span class="file-size">@FormatSize(entry.Info.Size)</span>
                    <span class="file-type">@entry.Info.Type</span>
                }
                <button class="remove-button" @onclick="() => RemoveFile(entry)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxFileSize = 10 * 1024 * 1024; // 10 MB

    private bool _isDragOver;
    private InputFile? _inputFile;
    private readonly List<FileEntry> _files = new();

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private void HandleDragOver() => _isDragOver = true;
    private void HandleDragLeave() => _isDragOver = false;

    private async Task HandleDrop(DragEventArgs e) => _isDragOver = false;

    private async Task HandleFileSelection(InputFileChangeEventArgs e)
    {
        foreach (var file in e.GetMultipleFiles(int.MaxValue))
        {
            var info = new FileInfo(file.Name, file.Size, file.ContentType);
            string? error = file.Size > MaxFileSize
                ? $"File exceeds the 10 MB limit ({FormatSize(file.Size)})"
                : null;
            _files.Add(new FileEntry(info, error));
        }

        await NotifyParent();
    }

    private async Task RemoveFile(FileEntry entry)
    {
        _files.Remove(entry);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var accepted = _files
            .Where(f => f.Error is null)
            .Select(f => f.Info)
            .ToList();
        await OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    private record FileEntry(FileInfo Info, string? Error);
}

.file-drop-zone {
    border: 2px dashed #6c757d;
    border-radius: 8px;
    padding: 2rem;
    text-align: center;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: pointer;
}

.file-drop-zone.drag-over {
    border-color: #0d6efd;
    background-color: rgba(13, 110, 253, 0.05);
}

.file-drop-zone p {
    margin: 0;
    color: #6c757d;
    font-size: 1rem;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-entry {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
}

.file-entry.file-error {
    border-color: #dc3545;
    background-color: rgba(220, 53, 69, 0.05);
}

.file-name {
    font-weight: 500;
}

.file-size,
.file-type {
    color: #6c757d;
    font-size: 0.875rem;
}

.error-message {
    color: #dc3545;
    font-size: 0.875rem;
}

.remove-button {
    margin-left: auto;
    background: none;
    border: 1px solid #dc3545;
    color: #dc3545;
    border-radius: 4px;
    padding: 0.25rem 0.5rem;
    cursor: pointer;
    font-size: 0.8rem;
}

.remove-button:hover {
    background-color: #dc3545;
    color: #fff;
}

