toolArgs.file_text:
.file-drop-zone {
    border: 2px dashed #6c757d;
    border-radius: 8px;
    padding: 2rem;
    text-align: center;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: pointer;
}

.file-drop-zone.drag-over {
    border-color: #0d6efd;
    background-color: rgba(13, 110, 253, 0.05);
}

.file-drop-zone p {
    margin: 0;
    color: #6c757d;
    font-size: 1rem;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-entry {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
}

.file-entry.file-error {
    border-color: #dc3545;
    background-color: rgba(220, 53, 69, 0.05);
}

.file-name {
    font-weight: 500;
}

.file-size,
.file-type {
    color: #6c757d;
    font-size: 0.875rem;
}

.error-message {
    color: #dc3545;
    font-size: 0.875rem;
}

.remove-button {
    margin-left: auto;
    background: none;
    border: 1px solid #dc3545;
    color: #dc3545;
    border-radius: 4px;
    padding: 0.25rem 0.5rem;
    cursor: pointer;
    font-size: 0.8rem;
}

.remove-button:hover {
    background-color: #dc3545;
    color: #fff;
}

